const getOrderLinesByOrderID = `-- name: GetOrderLinesByOrderID :many
SELECT id, order_id, checkout_line_id, product_id, name, serial, description, unit_price, quantity, total_price, currency, created_at, updated_at FROM tbl_order_lines
WHERE order_id = ?
ORDER BY id ASC
`

func (q *Queries) GetOrderLinesByOrderID(ctx context.Context, orderID int64) ([]TblOrderLine, error) {
	rows, err := q.db.QueryContext(ctx, getOrderLinesByOrderID, orderID)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []TblOrderLine
	for rows.Next() {
		var i TblOrderLine
		if err := rows.Scan(
			&i.ID,
			&i.OrderID,
			&i.CheckoutLineID,
			&i.ProductID,
			&i.Name,
			&i.Serial,
			&i.Description,
			&i.UnitPrice,
			&i.Quantity,
			&i.TotalPrice,
			&i.Currency,
			&i.CreatedAt,
			&i.UpdatedAt,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Close(); err != nil {
		return nil, err
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

